+  /**
+   * Run a specific benchmark by name
+   */
+  async runByName(name: string): Promise<BenchmarkResult> {
+    const benchmark = this.benchmarks.get(name);
+    if (!benchmark) {
+      throw new Error(`Benchmark not found: ${name}`);
+    }
