+    const existing = this.memories.get(id);
+    if (!existing) {
+      return false;
+    }
+
+    const updated: Memory = {
+      ...existing,
+      ...updates,
+      id // Ensure ID cannot be changed
+    };
+
+    // Re-store with updates
+    await this.delete(id);
+    await this.store(updated);
+
+    return true;
+  }
+
+  /**
