+    if (this.dimension === 0) {
+      this.dimension = entry.embedding.length;
+    } else if (entry.embedding.length !== this.dimension) {
+      throw new Error(
+        `Embedding dimension mismatch: expected ${this.dimension}, got ${entry.embedding.length}`
+      );
+    }
