+    options: SelfAttentionConfig = {}
+  ): Promise<SelfAttentionResult> {
+    const startTime = performance.now();
+
+    // Validate input
+    if (!query || !Array.isArray(query)) {
+      throw new Error('Query must be a non-null array');
+    }
