+  private squaredDistance(a: Float32Array, b: Float32Array): number {
+    let sum = 0;
+    for (let i = 0; i < a.length; i++) {
+      const diff = a[i] - b[i];
+      sum += diff * diff;
+    }
+    return sum;
+  }
+
+  /**
+   * Check if the model has been trained
+   */
+  isTrained(): boolean {
+    return this.trained;
+  }
+
+  /**
+   * Get codebooks for serialization
+   */
+  getCodebooks(): Float32Array[] {
