+  }
+
+  /**
+   * Load pre-trained codebooks
+   *
+   * @param codebooks - Array of codebook Float32Arrays
+   * @param dimension - Original vector dimension
+   */
+  loadCodebooks(codebooks: Float32Array[], dimension: number): void {
