+  switch (type) {
+    case 'scalar-8bit':
+      return originalBytes / dimension; // 1 byte per value = 4x compression
+    case 'scalar-4bit':
+      return originalBytes / Math.ceil(dimension / 2); // 0.5 bytes per value = 8x compression
+    case 'product':
+      return originalBytes / numSubvectors; // 1 byte per subvector
+    default:
+      return 1;
+  }
